var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"읏차. 제대로 받았다.","JPN":"よいしょ。ちゃんと受け止めたよ。","ENG":"Hup! Gotcha.","TWN":"嘿咻，接到啦！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"루루? 쓰러진 거야?","JPN":"ルルちゃん？　倒れたの？","ENG":"Lulu? Is she okay?","TWN":"露露？她是暈倒嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠든 거야. 정확히는 악몽을 가져오는 중이고…….","JPN":"眠ったんだ。正確には悪夢を取り込んでいるところ……","ENG":"She’s just asleep. Well, gathering nightmares to be exact...","TWN":"是睡著，正確來說是正在帶走惡夢……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"괜찮은 거 맞지?","JPN":"本当に大丈夫なんだよね？","ENG":"But she's fine, right?","TWN":"她不會有事吧？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"애가 너무 종이처럼 팔랑거려서 걱정돼.","JPN":"紙のようにヒラヒラしてるから心配だなあ。","ENG":"I’m kinda worried because she’s so flimsy.","TWN":"她跟紙片人一樣，站都站不穩，有點不妥的感覺。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그렇지?! 나만 그런 게 아니라니까. 맨날 괜찮다고만 하고, 잘 쓰러지고 비틀대고. 밥도 제대로 안 먹고 잠도 제 때 안 자고. 걱정돼 죽겠어.","JPN":"でしょ！？　やっぱり私だけじゃないんだよ。いつも大丈夫って言って倒れてはふらふらしてるし。ご飯もちゃんと食べないし、ちゃんと寝ないし。もう本当心配で心配で。","ENG":"You are?! I’m not the only one who thinks that! She always claims to be fine, but she frequently faints, wobbles around, doesn't eat well, and doesn't even sleep! She worries me so much.","TWN":"是不是！不是只有我會擔心的嘛！她每次都說沒事，然後一天到晚暈倒，搖搖晃晃的，也不好好睡覺，想把我擔心死。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"푸흡.","JPN":"ぷっ。","ENG":"Pfft!","TWN":"噗。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아. 미안. 걱정된다는 사람 표정치고 너무 괜찮다는 표정이라.","JPN":"あ、ごめん。心配してるというわりには心配ないって顔してるから。","ENG":"Oh, sorry. It’s just that for someone who’s worried, your expression says otherwise.","TWN":"啊，抱歉，因為你嘴巴上說擔心，表情卻很淡定。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그럴 수밖에. 저렇게 걱정시키면서도 항상 멀쩡하게 돌아왔거든.","JPN":"……仕方ないじゃん。あんなに心配させてるくせに、いつも何ともなく帰ってきたんだから。","ENG":"Well... Even though she worries me, she has always returned safely.","TWN":"……沒辦法，雖然我每次都很擔心，但她每次都平安回來。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러니까, 믿어. 이번에도 잘 깨어날 거야.","JPN":"だから、信じてる。今度もちゃんと目を覚ますはずだよ。","ENG":"So, I trust her. She’ll be all right this time as well.","TWN":"我相信，她這次也會醒來的。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아주 보기 좋네. 구름처럼 몽글몽글해졌어.","JPN":"いい光景だね。雲のようにフワフワになった。","ENG":"That’s nice. Like a fluffy cloud.","TWN":"真美的畫面，好像雲朵一樣軟綿綿的。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나도…….","JPN":"私も……","ENG":"Me too...","TWN":"我也是……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"기분 탓인지 모르겠는데, 바깥이 더 어두워진 것 같지 않아?","JPN":"気のせいかもしれないけど、なんだか外が暗くなった気がしない？","ENG":"Hey, um... Is it just me or did it get darker outside?","TWN":"是我感覺的問題嗎？怎麼覺得外面好像變得更暗了？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러게? 아까보다 훨씬 어두워.","JPN":"そうだね。さっきよりずっと暗い。","ENG":"Yeah... It's gotten significantly darker.","TWN":"對啊，跟剛才比起來，現在又更暗了。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시가 뚫어 둔 벽이 꼭 블랙홀처럼 보일 정도로 깜깜해.","JPN":"ドロシーちゃんがあけた穴が、まるでブラックホールに見えるくらい真っ暗だね。","ENG":"That hole in the wall Dorothy made now looks like a black hole.","TWN":"暗到桃樂絲剛踹破的牆壁看起來像黑洞一樣。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……달이 사라졌어. 아까까지만 해도 슈퍼문처럼 떠 있었는데.","JPN":"……月が消えた。さっきまでスーパームーンのように浮いてたのに。","ENG":"The moon’s gone. It was there shining bright a few moments ago...","TWN":"……月亮消失了，剛剛明明還像超級月亮一樣掛在空中。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"뭐?! 구, 구름에 가려진 거 아닐까?","JPN":"えっ！？　く、雲に隠れたんじゃないの？","ENG":"What?! M-maybe it’s just covered by clouds?","TWN":"什麼？！會不會是被雲遮住？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};